from difflib import SequenceMatcher
from itertools import product

def is_near_duplicate(
    new_scenario: str,
    existing_scenarios: list[str],
    threshold: float = 0.75,
) -> bool:
    """Return True if the new scenario is too similar to any existing one."""
    for existing in existing_scenarios:
        ratio = SequenceMatcher(None, new_scenario.lower(), existing.lower()).ratio()
        if ratio >= threshold:
            return True
    return False


class ScenarioCoverageTracker:
    """Track which axis × level combinations have been covered."""

    def __init__(self, axes: dict[str, list[str]]):
        self.axes = axes
        # Each key is a frozenset of (axis, value) pairs — one per scenario
        self._covered: set[frozenset] = set()
        # All target combinations (one value per axis)
        self._all_combos: list[frozenset] = [
            frozenset(zip(axes.keys(), combo))
            for combo in product(*axes.values())
        ]

    def record(self, axis_values: dict[str, str]) -> None:
        self._covered.add(frozenset(axis_values.items()))

    @property
    def coverage_pct(self) -> float:
        if not self._all_combos:
            return 100.0
        covered = sum(1 for c in self._all_combos if c in self._covered)
        return 100.0 * covered / len(self._all_combos)

    def uncovered_axes(self) -> list[dict[str, str]]:
        """Return axis-value dicts for combinations not yet seen."""
        return [
            dict(combo)
            for combo in self._all_combos
            if combo not in self._covered
        ]

    def next_gap_prompt(self) -> str | None:
        """Build a targeted prompt suffix to fill the next coverage gap."""
        gaps = self.uncovered_axes()
        if not gaps:
            return None
        gap = gaps[0]
        parts = ", ".join(f"{k}={v}" for k, v in gap.items())
        return f"The scenario MUST represent the combination: {parts}."


def generate_until_coverage(
    spec: ScenarioSpec,
    target_pct: float = 90.0,
    max_iterations: int = 20,
) -> list[Scenario]:
    """Keep generating batches until coverage target is met or budget exhausted."""
    tracker = ScenarioCoverageTracker(spec.axes)
    all_scenarios: list[Scenario] = []
    seen_descriptions: list[str] = []

    for iteration in range(max_iterations):
        if tracker.coverage_pct >= target_pct:
            break

        # Inject gap prompt if coverage is low
        gap_suffix = tracker.next_gap_prompt() or ""
        modified_spec = ScenarioSpec(
            domain=spec.domain,
            seed_context=spec.seed_context + (f"\n\nConstraint: {gap_suffix}" if gap_suffix else ""),
            constraints=spec.constraints,
            axes=spec.axes,
            count=min(spec.count, 3),  # smaller batches when targeting gaps
            audience=spec.audience,
        )
        batch = generate_scenarios(modified_spec)

        for scenario in batch:
            if is_near_duplicate(scenario.description, seen_descriptions):
                continue
            seen_descriptions.append(scenario.description)
            all_scenarios.append(scenario)
            # Record coverage: look for tag matches against axis values
            axis_values = {
                axis: next((v for v in values if v.lower() in " ".join(scenario.tags).lower()), "unknown")
                for axis, values in spec.axes.items()
            }
            tracker.record(axis_values)

        print(f"Iteration {iteration + 1}: {tracker.coverage_pct:.0f}% coverage, "
              f"{len(all_scenarios)} scenarios")

    return all_scenarios
